#include "tdfa/TaggedDFA.h"
#include <cctype>
namespace tdfa { TaggedMatch TaggedDFA::matchFloat(const std::string&s)const{TaggedMatch m={false,"",std::vector<std::string>(),0,"",std::vector<int>()};size_t i=0;while(i<s.size()&&std::isdigit((unsigned char)s[i]))i++;if(i==0||i>=s.size()||s[i]!='.')return m;size_t dot=i++;size_t f=i;while(i<s.size()&&std::isdigit((unsigned char)s[i]))i++;if(f==i||i!=s.size())return m;m.matched=true;m.token="TOKEN_FLOAT";m.groups.push_back(s.substr(0,dot));m.groups.push_back(s.substr(f));m.tagOperations=4;return m;} TaggedMatch TaggedDFA::matchString(const std::string&s)const{TaggedMatch m={false,"",std::vector<std::string>(),0,"",std::vector<int>()};if(s.size()<2||s[0]!='\"'||s[s.size()-1]!='\"')return m;m.matched=true;m.token="TOKEN_STRING";m.rawContent=s.substr(1,s.size()-2);for(size_t i=0;i<m.rawContent.size();++i)if(m.rawContent[i]=='\\'&&i+1<m.rawContent.size()){m.escapePositions.push_back((int)i);m.tagOperations++;i++;}return m;} }
